// Correlate recently shipped features with new bugs
const doneIssues = $('Fetch Recently Done Issues').first().json;
const bugIssues = $('Fetch Recent Bugs').first().json;

const shipped = (doneIssues.issues || []).map(i => ({
  key: i.key,
  summary: i.fields?.summary || '',
  labels: i.fields?.labels || [],
  updated: i.fields?.updated || ''
}));

const bugs = (bugIssues.issues || []).map(i => ({
  key: i.key,
  summary: i.fields?.summary || '',
  priority: i.fields?.priority?.name || 'Medium',
  status: i.fields?.status?.name || '',
  description: (() => {
    const desc = i.fields?.description;
    if (!desc) return '';
    if (typeof desc === 'string') return desc;
    // ADF format - extract text
    try {
      return JSON.stringify(desc).substring(0, 500);
    } catch (e) {
      return '';
    }
  })()
}));

const recentlyShipped = shipped.length;
const newBugs = bugs.length;
const criticalHighBugs = bugs.filter(b => ['Highest', 'High', 'Critical'].includes(b.priority)).length;
const escapeRate = recentlyShipped > 0 ? Math.round((newBugs / recentlyShipped) * 100) : 0;

// Correlate: check if bug summaries/descriptions reference shipped feature keys or similar terms
const correlations = [];
for (const bug of bugs) {
  const bugText = (bug.summary + ' ' + bug.description).toLowerCase();
  for (const feature of shipped) {
    const featureKey = feature.key.toLowerCase();
    const featureWords = feature.summary.toLowerCase().split(/\s+/).filter(w => w.length > 3);
    const keyMatch = bugText.includes(featureKey);
    const wordMatches = featureWords.filter(w => bugText.includes(w));
    if (keyMatch || wordMatches.length >= 2) {
      correlations.push({
        bug: bug.key,
        bugSummary: bug.summary,
        bugPriority: bug.priority,
        feature: feature.key,
        featureSummary: feature.summary,
        matchType: keyMatch ? 'key-reference' : 'keyword-overlap',
        matchedWords: wordMatches.slice(0, 5)
      });
    }
  }
}

const today = new Date().toISOString().split('T')[0];

// Build concerning section
let concerningText = '';
if (correlations.length > 0) {
  concerningText = correlations.map(c =>
    `- ${c.feature} (${c.featureSummary}) may relate to ${c.bug} (${c.bugSummary}) [${c.bugPriority}]`
  ).join('\n');
} else if (newBugs > 0) {
  concerningText = bugs.slice(0, 5).map(b =>
    `- ${b.key}: ${b.summary} [${b.priority}]`
  ).join('\n');
}

const hasIssues = newBugs > 0 || correlations.length > 0;

return [{
  json: {
    hasIssues,
    recentlyShipped,
    newBugs,
    criticalHighBugs,
    escapeRate,
    correlations,
    date: today,
    concerningText,
    shippedList: shipped.slice(0, 10).map(s => `${s.key}: ${s.summary}`).join('\n'),
    bugList: bugs.slice(0, 10).map(b => `${b.key}: ${b.summary} [${b.priority}]`).join('\n')
  }
}];
